use num_bigint::BigInt;
use num_traits::Zero;

use crate::engine::{Delta, Q, for_each_residual, residual_perturbation};

/// Exact coherence gradient: ∂C/∂ε for each off-diagonal (r,s).
#[derive(Debug, Clone)]
pub struct CoherenceGradient {
    pub dim: usize,
    pub gradient: Vec<Vec<Q>>,
    pub best_direction: (usize, usize),
    pub best_gradient: Q,
}

/// Compute the exact coherence gradient analytically.
///
/// ∂C/∂ε_{rs} = Σ_{triples} sign(R_{ijk,l}) · ∂R_{ijk,l}/∂ε_{rs}
///
/// Cohomological gradient — no squaring. The sign of each residual
/// determines the direction. The perturbation determines the magnitude.
/// No R × ∂R multiplication — no denominator compounding.
///
/// One call to for_each_residual. One source of truth.
pub fn compute_coherence_gradient(delta: &Delta) -> CoherenceGradient {
    let n = delta.dim;
    let mut gradient = vec![vec![Q::zero(); n]; n];

    // Accumulate gradient over all residuals — single iteration
    for r in 0..n {
        for s in 0..n {
            if r == s { continue; }
            let mut dc = Q::zero();
            for_each_residual(delta, |i, j, k, l, residual| {
                let d_residual = residual_perturbation(delta, i, j, k, l, r, s);
                if !d_residual.is_zero() {
                    // ∂(R²)/∂ε = 2R · ∂R/∂ε — L2 squared norm gradient
                    let two_r = residual + residual;
                    dc += &two_r * &d_residual;
                }
            });
            gradient[r][s] = dc;
        }
    }

    // Find best direction
    let mut best_dir = (0, 1);
    let mut best_grad = Q::zero();
    let mut first = true;
    for r in 0..n {
        for s in 0..n {
            if r == s { continue; }
            if first || gradient[r][s] < best_grad {
                best_grad = gradient[r][s].clone();
                best_dir = (r, s);
                first = false;
            }
        }
    }

    CoherenceGradient { dim: n, gradient, best_direction: best_dir, best_gradient: best_grad }
}

/// Exact second derivative: ∂²C/(∂ε_{rs} · ∂ε_{pq}).
///
/// ∂²C/(∂ε₁·∂ε₂) = 2·Σ_{triples} ∂R/∂ε₁ · ∂R/∂ε₂
///
/// One call to for_each_residual. Same iterator as gradient.
pub fn exact_hessian_entry(
    delta: &Delta,
    r1: usize, s1: usize,
    r2: usize, s2: usize,
) -> Q {
    let two = Q::new(BigInt::from(2), BigInt::from(1));
    let mut h = Q::zero();
    for_each_residual(delta, |i, j, k, l, _residual| {
        let d1 = residual_perturbation(delta, i, j, k, l, r1, s1);
        if d1.is_zero() { return; }
        let d2 = residual_perturbation(delta, i, j, k, l, r2, s2);
        if d2.is_zero() { return; }
        h += &d1 * &d2;
    });
    &two * &h
}

/// Compute the full exact Hessian for all independent shear directions.
pub fn compute_exact_hessian(delta: &Delta) -> (Vec<(usize, usize)>, Vec<Vec<Q>>) {
    let n = delta.dim;
    let mut dirs: Vec<(usize, usize)> = Vec::new();
    for r in 0..n {
        for s in 0..n {
            if r != s { dirs.push((r, s)); }
        }
    }
    let d = dirs.len();
    let mut hessian = vec![vec![Q::zero(); d]; d];
    for a in 0..d {
        for b in a..d {
            let (r1, s1) = dirs[a];
            let (r2, s2) = dirs[b];
            let h = exact_hessian_entry(delta, r1, s1, r2, s2);
            hessian[a][b] = h.clone();
            hessian[b][a] = h;
        }
    }
    (dirs, hessian)
}

/// Gradient hint: steepest descent direction with conservative step.
pub fn gradient_hint(delta: &Delta) -> (usize, usize, Q) {
    let grad = compute_coherence_gradient(delta);
    let (i, j) = grad.best_direction;
    let suggested_eps = if grad.best_gradient < Q::zero() {
        Q::new(BigInt::from(1), BigInt::from(20))
    } else {
        Q::zero()
    };
    (i, j, suggested_eps)
}

